<?php
namespace Tests\Feature;use App\Models\Monster;use App\Models\MonsterLootEntry;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Database\QueryException;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\DB;use Tests\TestCase;class MonsterLootSchemaTest extends TestCase{use RefreshDatabase;public function test_schema_relations_unique_and_restrict(){ $this->seed(WorldCatalogSeeder::class);$wolf=Monster::where('code','grey_wolf')->first();$this->assertCount(2,$wolf->lootEntries);$entry=$wolf->lootEntries->first();try{MonsterLootEntry::create($entry->only(['monster_id','item_id','drop_chance_basis_points','minimum_quantity','maximum_quantity','status','sort_order']));$this->fail();}catch(QueryException $e){$this->assertTrue(true);}try{$entry->item->delete();$this->fail();}catch(QueryException $e){$this->assertDatabaseHas('items',['id'=>$entry->item_id]);}$table=DB::selectOne("SELECT ENGINE,TABLE_COLLATION FROM information_schema.TABLES WHERE TABLE_SCHEMA=DATABASE() AND TABLE_NAME='monster_loot_entries'");$this->assertSame('InnoDB',$table->ENGINE);$this->assertSame('utf8mb4_unicode_ci',$table->TABLE_COLLATION);}}
